// components/layout/FieldWrapper.native.tsx

import React, {useCallback, useEffect, useMemo, useRef} from "react";
import type {FieldValues} from "react-hook-form";
import {useWatch} from "react-hook-form";
import {useFieldLogic} from "../../hooks";
import type {FieldWrapperProps, GroupFieldConfigs} from "@lmb-it/kitsconcerto-types";
import {Flex} from "../../../../";
import {createStyleContext, resolveResponsiveValue} from "@lmb-it/kitsconcertomobile/Factory/helpers/style";

/**
 * Native layout contract:
 * - Container MUST be flex-row + flex-wrap
 * - Grid semantics are approximated via percentages
 *
 * Supported mappings:
 * - columns           -> virtual column count
 * - colSpan           -> width %
 * - colOffset         -> marginLeft %
 * - columnGap         -> item horizontal padding
 * - rowGap            -> item vertical padding
 * - rowSpan           -> minHeight approximation
 *
 * Ignored (grid-only semantics):
 * - templateAreas
 * - area
 * - gridTemplateRows
 * - gridTemplateColumns
 * - rowStart / rowEnd
 * - colStart / colEnd
 */

const DEFAULT_COLUMNS = 12;
const DEFAULT_ROW_HEIGHT = 56;

export const FieldWrapper = <T extends FieldValues>({
                                                        element,
                                                        control,
                                                        getValues,
                                                        setFocusedField,
                                                        focusedField,
                                                        children,
                                                        grid,
                                                        onGridChange,
                                                        groupField,
                                                    }: FieldWrapperProps<T>) => {
    /* ---------------- helpers (no hooks) ---------------- */

    const currentLayout = useRef<any>(null);
    const resolveDepPath = (dep: string, groupField?: GroupFieldConfigs<T>['groupField']): string => {
        if (!groupField || groupField.index === undefined || groupField.index < 0) return dep;

        const parts = dep.split(".");
        const {name, index} = groupField;

        // Must be "<groupName>.<something...>"
        if (parts.length < 2) return dep;

        // Match the group name (first segment)
        if (parts[0] !== name) return dep;

        // Replace "current" (second segment) with numeric index
        if (parts[1] === "current") {
            parts[1] = String(index);
            return parts.join(".");
        }

        return dep;
    };

    const flattenPaths = (obj: any, prefix = ''): string[] =>
        Object.keys(obj ?? {}).flatMap((key) => {
            const path = prefix ? `${prefix}.${key}` : key;
            return typeof obj[key] === 'object' && obj[key] !== null
                ? [path, ...flattenPaths(obj[key], path)]
                : [path];
        });

    // 1. Determine which fields to watch for changes.
    const dependencies = useMemo(() => {
        const deps = new Set<string>([...(element.deps ?? []), ...(element.logic?.deps ?? [])]);

        if (deps.has('*')) {
            return flattenPaths(getValues());
        }

        return Array.from(deps).map((d) => resolveDepPath(d, groupField));
    }, [element, groupField]);


    // 2. Efficiently watch only the necessary fields.
    const watchedValues = useWatch({
        name: dependencies as any,
        compute:(fieldValue)=>{
            return fieldValue
        },
        exact:true,
        disabled:dependencies.length === 0
    });

    useEffect(() => {
        // console.log('watchedValues', watchedValues)
    }, [watchedValues]);
    // This single hook provides all the necessary logic and state for the field.
    const fieldLogic = useFieldLogic({element, control, getValues, isFocused: focusedField === element.id, groupField, watchedValues});

    const {
        field,
        isShown,
        layout,
        style:elementStyle,
        animation
    } = fieldLogic;
    const isFocused = focusedField === field.name;

    const onFocus = useCallback(() => setFocusedField(field.name), [setFocusedField, field.name]);
    const onBlur: React.FocusEventHandler<any> = useCallback((event) => {
        const cl = event.target['className'];
        // @ts-ignore
        if(!cl || cl.includes(`${element.id}_option_item`) || cl.includes(`p-multiselect-filter`)){
            return;
        }
        setFocusedField('');
        field.onBlur(); // Call the original onBlur from react-hook-form
    }, [setFocusedField, field.onBlur]);

    // Grid layout effect — MUST be before any conditional return (Rules of Hooks)
    useEffect(() => {
        if(layout.colSpan && currentLayout.current != JSON.stringify(layout)){
            const ctx = createStyleContext();

            const colSpan = resolveResponsiveValue<string | number>(layout.colSpan, ctx);

            onGridChange?.(colSpan?.toString() ?? '12')

            currentLayout.current = JSON.stringify(layout)
        }

    }, [layout]);

    // If the logic dictates this field should not be shown, render nothing.
    if (!isShown || !children) {
        return null;
    }



    // @ts-ignore
    return <Flex {...elementStyle?.container} {...animation}
                 zIndex={isFocused ? 1000 : ('auto' as unknown as number)}
                 w={'100%'} onTouchStart={onFocus}>
        {children(fieldLogic)}
    </Flex>
};
